  KnowledgeEntry(
      id: 'cdc-natural-disasters-cleanup-safety-chunk-0009',
      title: 'Guidelines for Cleaning Safely After a Disaster | Natural Disasters | CDC #9 If electrical circuits and electrical equipment',
      summary: 'If electrical circuits and electrical equipment have gotten wet or are in or near water, turn off the power at the main breaker or fuse on the service panel.',
      steps: [
        'If you must enter standing water to access the main power switch, then call an electrician to turn it off.',
        'Never turn power on or off or use an electric tool or appliance while standing in water.',
        'Do not connect generators to your home\'s electrical circuits without the approved, automatic-interrupt devices.',
        'If a generator is on line when electrical service is restored, it can become a major fire hazard and it may endanger line workers helping to restore power in your area.',
      ],
