  KnowledgeEntry(
      id: 'cdc-natural-disasters-power-outage-chunk-0004',
      title: 'What to Do to Protect Yourself During a Power Outage | Natural Disasters | CDC #4 Food, water, and medication safety Food safety K',
      summary: 'Food, water, and medication safety Food safety Keep refrigerator and freezer doors closed as much as possible while the power is out.',
      steps: [
        'A full freezer will keep food safe for 48 hours (24 hours if half-full) without power if you don\'t open the door.',
        'Your refrigerator will keep food safe for up to 4 hours without power if you don\'t open the door.',
        'Throw out the following foods: All perishable foods (including meat, chicken and other poultry, fish, eggs, and leftovers) in your refrigerator when the power has been off for 4 hours or more.',
        'All perishable foods in your freezer if they have thawed.',
      ],
      contraindications: const <String>[],
