  KnowledgeEntry(
      id: 'nps-wilderness-travel-basics-chunk-0004',
      title: 'Wilderness Travel Basics - Olympic National Park (U.S. National Park Service) #4 Magnetic North is located about a thousand miles',
      summary: 'Magnetic North is located about a thousand miles south of true north in the Canadian Arctic, and slowly moves its location each year.',
      steps: [
        'The difference between true north and magnetic north is called magnetic declination.',
        'At Olympic, each year the magnetic declination moves westerly by 7.5 minutes.',
        'The current declination is approximately 15.5 degrees east.',
        'For any hike off-trail, or when snow obscures the trail, map and compass navigation skills and route-finding skills are a must.',
      ],
