  KnowledgeEntry(
      id: 'fm-21-76-survival-chunk-0345',
      title: 'FM 21-76 Survival Manual #345 Page 219.',
      summary: 'Page 219.',
      steps: [
        'High temperatures, heavy rainfall, and oppressive humidity characterize equatorial and subtropical regions, except at high altitudes.',
        'At low altitudes, temperature variation is seldom less than 10 degrees C (50 degrees F) and is often more than 35 degrees C (95 degrees F).',
        'At altitudes over 1,500 meters (4,921 feet), ice often forms at night.',
