  KnowledgeEntry(
      id: 'fm-21-76-survival-chunk-0644',
      title: 'FM 21-76 Survival Manual #644 Page 391.',
      summary: 'Page 391.',
      steps: [
        'B-1 Appendix B Edible and Medicinal Plants In a survival situation, plants can provide food and medicine.',
        'Their safe use requires absolutely positive identification, knowing how to prepare them for eating, and knowing any dangerous properties they might have.',
        'Familiarity with botanical structures of plants and information on where they grow will make them easier to locate and identify.',
        'This appendix provides pictures, descriptions, habitats and distribution, and edible parts of the most common plants that you might encounter.',
      ],
      contraindications: const <String>[],
