  KnowledgeEntry(
      id: 'fm-21-76-survival-chunk-0648',
      title: 'FM 21-76 Survival Manual #648 Page 395.',
      summary: 'Page 395.',
      steps: [
        'FM 3-05.70 B-5 Almond Prunus amygdalus Description: The almond tree, which sometimes grows to 12.2 meters (40 feet), looks like a peach tree.',
        'The fresh almond fruit resembles a gnarled, unripe peach and grows in clusters.',
        'The stone (the almond itself) is covered with a thick, dry, woolly skin.',
        'Habitat and Distribution: Almonds are found in the scrub and thorn forests of the tropics, the evergreen scrub forests of temperate areas, and in desert scrub and waste in all climatic zones.',
      ],
      contraindications: const <String>[],
