  KnowledgeEntry(
      id: 'fm-21-76-survival-chunk-0650',
      title: 'FM 21-76 Survival Manual #650 Page 397.',
      summary: 'Page 397.',
      steps: [
        'FM 3-05.70 B-7 Arctic willow Salix arctica Description: The arctic willow is a shrub that never exceeds more than 60 centimeters (24 inches) in height and grows in clumps that form dense mats on the tundra.',
        'Habitat and Distribution: The arctic willow is common on tundras in North America, Europe, and Asia.',
        'You can also find it in some mountainous areas in temperate regions.',
        'Edible Parts: You can collect the succulent, t ender young shoots of the arctic willow in early spring.',
      ],
      contraindications: const <String>[],
