  KnowledgeEntry(
      id: 'fm-21-76-survival-chunk-0846',
      title: 'FM 21-76 Survival Manual #846 Page 629.',
      summary: 'Page 629.',
      steps: [
        'F-1 Appendix F Dangerous Fish and Mollusks Fish and mollusks may be one of your major sources of food.',
        'Therefore, it is wise to know which ones are dangerou s, what the dangers of the various fish are, what precautions to take, and what to do if you are injured by one of these fish.',
        'Fish and mollusks will present a danger in one of three ways—by attacking and biting you, by injecting toxic venom into you through venomous spines or tentacles, and through eating fish or mollusks whose flesh is toxic.',
        'The danger of actually encountering one of these dangerous fish is relatively small, but it is still significant.',
      ],
      contraindications: const <String>[],
