  KnowledgeEntry(
      id: 'fm-21-76-survival-chunk-0868',
      title: 'FM 21-76 Survival Manual #868 Page 650.',
      summary: 'Page 650.',
      steps: [
        'H-1 Appendix H Clouds: Foretellers of Weather About 200 years ago an Englishman classified clouds according to what they looked like to a person seeing them from the ground.',
        'He grouped them into three classes and gave them Latin names: cirrus, cumulus, and stratus.',
        'These three names, alone and combined with other Latin words, are still used to identify different cloud formations.',
        'By being familiar with the different cloud formation and what weather they portend, you can take appropriate action for your protection.',
      ],
      contraindications: const <String>[],
