  KnowledgeEntry(
      id: 'hf-choking-alone',
      title: '独自噎住时的自救',
      summary: '先设法呼叫急救，再借助硬物进行自我腹部冲击。',
      steps: [
        'Call 911 first, even though you will not be able to speak.',
        'Leave the phone connected.',
        '911 can pinpoint your location and send emergency help.',
        'Use a landline if available.',
      ],
      contraindications: [
        '不要反复喝水试图冲下去',
        '不要继续吞咽更多食物',
      ],
      escalation: '若无法发声、呼吸迅速恶化或即将失去意识，必须尽快引起他人注意并呼救。',
      tags: [
        '窒息',
        '独自噎住',
        'self choking',
        'alone choking',
        'huggingface',
        'medical qa',
      ],
      aliases: [
