  KnowledgeEntry(
      id: 'hf-choking-infant',
      title: '婴儿噎住时的急救',
      summary: '婴儿不能直接做成人海姆立克，要用拍背和胸部按压。',
      steps: [
        'a baby is choking, you need to use different first aid techniques to help them.',
        'Start with back blows:',
        'Lay the baby across your forearm, face down.',
        'Support them with your lap or upper thigh.',
      ],
      contraindications: [
        '不要盲目伸手抠看不见的异物',
        '不要给完全噎住的婴儿喂水',
      ],
      escalation: '若婴儿反应差、发青或失去意识，立刻呼叫急救并按婴儿 CPR 流程处理。',
