  KnowledgeEntry(
      id: 'hf-electrical-burn',
      title: '电击伤与电烧伤处理',
      summary: '先断电再接触伤者，外观轻也可能有严重内伤。',
      steps: [
        'someone suffers an electrical burn, do not touch them if they are still in contact with the electrical source.',
        'Turn off the power or use a non-conductive object to separate them from the source.',
        'Once it is safe, check for responsiveness and breathing, and call emergency services immediately.',
        'After ensuring the person is no longer in contact with the electrical source, cover the burn with a sterile, non-stick bandage.',
      ],
      contraindications: [
        '不要在未断电前直接触碰伤者',
        '不要只看表面小伤就掉以轻心',
      ],
      escalation: '电击伤可能伴发心律失常和深部组织损伤，应尽快急救和医疗评估。',
      tags: [
        '烧伤',
        '电击',
        '电烧伤',
