  KnowledgeEntry(
      id: 'hf-fracture-stabilization',
      title: '骨折后的现场稳定',
      summary: '先固定再搬运，减少再次错位和出血。',
      steps: [
        'Any injury to your limbs, hands, and feet needs to be treated as a broken bone until an X-ray can be done.',
        'While broken bones or fractures do need medical treatment, they do not all require an emergency trip to the hospital.',
        'First aid steps can help stabilize the bone until you can see a healthcare provider.',
        'Call 911 if:',
      ],
      contraindications: [
        '不要强行复位',
        '不要让伤者带伤行走',
      ],
      escalation: '若骨头外露、脊柱受伤或合并大量出血，应立即急救转运。',
      tags: [
        '致命外伤',
        '骨折',
        'fracture',
        'broken bone',
        '夹板',
        'huggingface',
        'medical qa',
