  KnowledgeEntry(
      id: 'merck-burns-chunk-0001',
      title: 'Burns - Injuries and Poisoning - MSD Manual Consumer Version #1 Burns By Damien Wilson Carter , MD , Tufts Unive',
      summary: 'Burns By Damien Wilson Carter , MD , Tufts University School of Medicine Reviewed/Revised Modified Sept 2024 v825445 Burns are injuries to tissue that result from heat, electricity',
      steps: [
        'Classification | Symptoms | Complications | Diagnosis | Treatment | Prognosis | Multimedia | Burns cause varying degrees of pain, blisters, swelling, and skin loss.',
        'Small, shallow burns may need only to be kept clean and to have an antibiotic salve applied.',
        'Deep, extensive burns can cause serious complications, such as shock and severe infections.',
        'People with deep or extensive burns may require intravenous fluids, surgery, and rehabilitation, often at a burn center.',
      ],
