  KnowledgeEntry(
      id: 'merck-burns-chunk-0005',
      title: 'Burns - Injuries and Poisoning - MSD Manual Consumer Version #5 Image provided by Steven E.',
      summary: 'Image provided by Steven E.',
      steps: [
        'Wolf, MD.',
        'Burns are classified as minor, moderate, or severe.',
        'These classifications may not correspond to a person’s understanding of those terms.',
        'For example, doctors may classify a burn as minor even though it can cause the person significant pain and interfere with normal activities.',
      ],
