  KnowledgeEntry(
      id: 'merck-burns-chunk-0011',
      title: 'Burns - Injuries and Poisoning - MSD Manual Consumer Version #11 Full-thickness burns, burns occurring in the ver',
      summary: 'Full-thickness burns, burns occurring in the very young or the very old, and burns involving the hands, feet, face, or genitals are usually best treated at burn centers.',
      steps: [
        'Burn centers are hospitals that are specially equipped and staffed to care for burn victims.',
        'Superficial minor burns Superficial minor burns are immediately cooled with room temperature water for several minutes, if possible.',
        'Chemical burns may need to be rinsed for longer periods.',
        'The burn is carefully cleansed to prevent infection.',
      ],
      contraindications: const <String>[],
