  KnowledgeEntry(
      id: 'merck-burns-chunk-0014',
      title: 'Burns - Injuries and Poisoning - MSD Manual Consumer Version #14 Any dead skin and broken blisters should be remo',
      summary: 'Any dead skin and broken blisters should be removed by a health care practitioner before the antibiotic salve or dressing is applied.',
      steps: [
        'In addition, keeping a deeply burned arm or leg elevated above the heart for the first few days reduces swelling and pain.',
        'Compression dressings, such as elastic wraps, may also help reduce swelling and improve wound healing.',
        'The burn may require admission to a hospital or frequent re-examination at a hospital or doctor’s office, possibly as often as daily for the first few days.',
        'A skin graft may be needed to replace burned skin that will not heal.',
      ],
