  KnowledgeEntry(
      id: 'merck-burns-chunk-0015',
      title: 'Burns - Injuries and Poisoning - MSD Manual Consumer Version #15 The incisions allow the donor skin to be stretch',
      summary: 'The incisions allow the donor skin to be stretched to cover a much larger area (often several times the area of the original piece of skin).',
      steps: [
        'Meshed grafts are used in areas where appearance is less of a concern and when burns involve more than 20% of the body surface and donor skin is scarce.',
        'Meshed grafts heal with an uneven gridlike appearance, sometimes with excessive scarring.',
        'After any dead tissue is removed and the wound is clean, a surgeon sews or staples the skin graft over the burned area.',
        'Artificial skin can also be used.',
      ],
