  KnowledgeEntry(
      id: 'merck-burns-chunk-0016',
      title: 'Burns - Injuries and Poisoning - MSD Manual Consumer Version #16 Physical and occupational therapy usually are ne',
      summary: 'Physical and occupational therapy usually are needed to prevent immobility caused by scarring around the joints and to help people function if joint motion is limited.',
      steps: [
        'Stretching exercises are started within the first few days after the burn.',
        'Splints are applied to ensure that joints that are likely to be immobile rest in positions that are least likely to lead to contractures.',
        'The splints are left in place except when the joints are moved.',
        'If a skin graft has been used, therapy is not started for less than 1 to more than 3 days after the graft is attached so that the healing graft is not disturbed.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Burns - Injuries and Poisoning - MSD Manual Consumer Version',
