  KnowledgeEntry(
      id: 'merck-choking-chunk-0001',
      title: 'Choking - Injuries and Poisoning - MSD Manual Consumer Version #1 Choking By Jaime Jordan , MD , UCLA School of Me',
      summary: 'Choking By Jaime Jordan , MD , UCLA School of Medicine Reviewed/Revised Modified Jul 2024 v829459 First Aid for Choking | Multimedia | Maneuvers to relieve choking are frequently l',
      steps: [
        'Adults most often choke on a piece of food, such as a large piece of meat.',
        'Infants do not have well-developed swallowing reflexes and may choke if given small, rounded foods such as peanuts or hard candies.',
        'Children, especially toddlers, also may choke on balloons, toys, coins, other inedible objects that they place in their mouth, and foods (particularly rounded, smooth foods, such as hot dogs, round candies, nuts, beans, and grapes).',
        'Coughing may be the first symptom and is often so severe that the person cannot ask for help.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Choking - Injuries and Poisoning - MSD Manual Consumer Version',
