  KnowledgeEntry(
      id: 'merck-choking-chunk-0002',
      title: 'Choking - Injuries and Poisoning - MSD Manual Consumer Version #2 If only 1 rescuer is available, wait to call for',
      summary: 'If only 1 rescuer is available, wait to call for help until after trying to clear the choking person\'s airway.',
      steps: [
        'Performing Abdominal Thrusts (Heimlich Maneuver) The rescuer stands behind the person and encircles the person\'s abdomen with the arms.',
        'With 1 hand, the rescuer forms a fist and clasps the other hand around the fist.',
        'The rescuer places the hands halfway between the breastbone and navel and thrusts the hands inward and upward.',
        'A strong cough often expels the object from the airway.',
      ],
      contraindications: const <String>[],
