  KnowledgeEntry(
      id: 'merck-home-topic-0001-chunk-0001',
      title: 'Amyloidosis - Blood Disorders - MSD Manual Consumer Version #1 Amyloidosis By John L.',
      summary: 'Amyloidosis By John L.',
      steps: [
        'Berk , MD , Amyloidosis Center, Boston University Medical Center; Vaishali Sanchorawala , MD , Boston University School of Medicine and Boston Medical Center Reviewed/Revised Mar 2025 | Modified Mar 2026 v831725 Amyloidosis is a rare disease in which abnormally folded proteins form into collections called amyloid fibrils that accumulate in various tissues and organs, sometimes leading to organ dysfunction, organ failure, and death.',
        'Causes | Forms of Amyloidosis | Symptoms | Diagnosis | Treatment | Prognosis | Multimedia | The symptoms and severity of amyloidosis depend on which vital organs are affected.',
        'Diagnosis is made by obtaining a sample of tissue (biopsy) and examining it under a microscope.',
        'There are many forms of amyloidosis, and other testing is required to identify the form and its cause.',
      ],
      contraindications: const <String>[],
