  KnowledgeEntry(
      id: 'merck-home-topic-0001-chunk-0002',
      title: 'Amyloidosis - Blood Disorders - MSD Manual Consumer Version #2 All types of amyloidosis involve a protein that',
      summary: 'All types of amyloidosis involve a protein that folds abnormally.',
      steps: [
        'The abnormally folded proteins clump together and accumulate in various body tissues as amyloid deposits.',
        'These deposits are made up of amyloid fibrils, which contain abnormal protein fibers that cannot be easily broken down by the body.',
        'These deposits interfere with normal function of the organ where they are located.',
        'All of these proteins are produced within the body and do not come from a person\'s diet.',
      ],
