  KnowledgeEntry(
      id: 'merck-home-topic-0002-chunk-0001',
      title: 'Anemia Due to Excessive Bleeding - Blood Disorders - MSD Manual Consumer Version #1 Anemia Due to Excessive Bleeding By Gloria F.',
      summary: 'Anemia Due to Excessive Bleeding By Gloria F.',
      steps: [
        'Gerber , MD , Johns Hopkins School of Medicine, Division of Hematology Reviewed/Revised Modified Apr 2024 v774594 Anemia due to excessive bleeding results when loss of red blood cells exceeds production of new red blood cells.',
        'Symptoms | Diagnosis | Treatment | When blood loss is rapid, blood pressure falls, and people may be dizzy.',
        'When blood loss occurs gradually, people may be tired, short of breath, and pale.',
        'Stool, urine, and imaging tests may be needed to determine the source of bleeding.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Anemia Due to Excessive Bleeding - Blood Disorders - MSD Manual Consumer Version',
