  KnowledgeEntry(
      id: 'merck-home-topic-0003-chunk-0001',
      title: 'Anemia of Chronic Disease - Blood Disorders - MSD Manual Consumer Version #1 Anemia of Chronic Disease (Anemia of Chronic Inf',
      summary: 'Anemia of Chronic Disease (Anemia of Chronic Inflammation) By Gloria F.',
      steps: [
        'Gerber , MD , Johns Hopkins School of Medicine, Division of Hematology Reviewed/Revised Apr 2024 | Modified Sept 2024 v774731 In anemia of chronic disease/inflammation, inflammation caused by an underlying disorder slows the production of red blood cells due to reduced iron availability.',
        'Diagnosis | Treatment | (See also Overview of Anemia .) Inflammatory anemia may develop in people with a chronic disease (for example, heart failure or chronic kidney disease ), a systemic autoimmune disease, an infection, or cancer.',
        'Worldwide, anemia of chronic disease is the second most common type of anemia.',
        'Chronic disease often leads to anemia, especially in older adults.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Anemia of Chronic Disease - Blood Disorders - MSD Manual Consumer Version',
