  KnowledgeEntry(
      id: 'merck-home-topic-0004-chunk-0001',
      title: 'Aplastic Anemia - Blood Disorders - MSD Manual Consumer Version #1 Aplastic Anemia (Hypoplastic Anemia) By Gloria F',
      summary: 'Aplastic Anemia (Hypoplastic Anemia) By Gloria F.',
      steps: [
        'Gerber , MD , Johns Hopkins School of Medicine, Division of Hematology Reviewed/Revised Modified Apr 2024 v9000466 Aplastic anemia is a disorder in which the cells of the bone marrow that develop into mature blood cells are destroyed, leading to low numbers of red blood cells, white blood cells, and/or platelets.',
        'Symptoms | Diagnosis | Treatment | When the bone marrow cells (stem cells) that develop into mature blood cells and platelets are damaged or destroyed, the bone marrow can shut down.',
        'This bone marrow failure is called aplastic anemia.',
        'The bone marrow failure leads to too few red blood cells ( anemia ), too few white blood cells ( leukopenia ), and too few platelets ( thrombocytopenia ).',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Aplastic Anemia - Blood Disorders - MSD Manual Consumer Version',
