  KnowledgeEntry(
      id: 'merck-home-topic-0004-chunk-0002',
      title: 'Aplastic Anemia - Blood Disorders - MSD Manual Consumer Version #2 When the cause of aplastic anemia cannot be diag',
      summary: 'When the cause of aplastic anemia cannot be diagnosed (called idiopathic aplastic anemia), the cause is likely an autoimmune disorder , in which the immune system suppresses bone m',
      steps: [
        'Other causes include Infection with viruses such as parvovirus (causes only pure red blood cell aplasia), Epstein Barr virus , or cytomegalovirus Radiation exposure Toxins (such as benzene) Chemotherapy agents and other medications (such as chloramphenicol) Pregnancy Hepatitis Symptoms of Aplastic Anemia Symptoms of aplastic anemia usually develop slowly over weeks to months.',
        'The anemia causes fatigue, weakness, and paleness.',
        'The leukopenia causes increased susceptibility to infection.',
        'The thrombocytopenia causes easy bruising and bleeding.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Aplastic Anemia - Blood Disorders - MSD Manual Consumer Version',
