  KnowledgeEntry(
      id: 'merck-home-topic-0005-chunk-0001',
      title: 'Autoimmune Hemolytic Anemia - Blood Disorders - MSD Manual Consumer Version #1 Autoimmune Hemolytic Anemia By Gloria F.',
      summary: 'Autoimmune Hemolytic Anemia By Gloria F.',
      steps: [
        'Gerber , MD , Johns Hopkins School of Medicine, Division of Hematology Reviewed/Revised Modified Apr 2024 v774756 Autoimmune hemolytic anemia is a group of disorders characterized by a malfunction of the immune system, resulting in the production of autoantibodies that attack red blood cells as if they were substances foreign to the body.',
        'Symptoms | Diagnosis | Treatment | Multimedia | Some people have no symptoms, and other people are tired, short of breath, and pale and may have jaundice or an enlarged spleen.',
        'Blood tests are used to detect anemia and determine the cause of the autoimmune reaction.',
        'Treatment is corticosteroids or other medications that suppress the immune system and sometimes, splenectomy (surgical removal of the spleen).',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Autoimmune Hemolytic Anemia - Blood Disorders - MSD Manual Consumer Version',
