  KnowledgeEntry(
      id: 'merck-home-topic-0006-chunk-0001',
      title: 'Glucose-6-Phosphate Dehydrogenase (G6PD) Deficiency - Blood Disorders - MSD Manual Consumer Version #1 Glucose-6-Phosphate Dehydrogenase (G6PD) Deficie',
      summary: 'Glucose-6-Phosphate Dehydrogenase (G6PD) Deficiency By Gloria F.',
      steps: [
        'Gerber , MD , Johns Hopkins School of Medicine, Division of Hematology Reviewed/Revised Apr 2024 | Modified Dec 2025 v50404284 Glucose-6-phosphate dehydrogenase (G6PD) deficiency is an inherited genetic disorder that can result in destruction of red blood cells (hemolysis) after an acute illness or use of certain medications.',
        'Symptoms | Diagnosis | Treatment | G6PD deficiency occurs because of a genetic defect in an enzyme involved in red blood cell metabolism.',
        'G6PD deficiency results in destruction of red blood cells in response to certain illnesses or medications.',
        'The destruction of red blood cells can cause symptoms, including yellowing of the skin and whites of the eyes, dark urine, and sometimes back or abdominal pain.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Glucose-6-Phosphate Dehydrogenase (G6PD) Deficiency - Blood Disorders - MSD Manual Consumer Version',
