  KnowledgeEntry(
      id: 'merck-home-topic-0006-chunk-0002',
      title: 'Glucose-6-Phosphate Dehydrogenase (G6PD) Deficiency - Blood Disorders - MSD Manual Consumer Version #2 Hemoglobin is the protein contained in red blood',
      summary: 'Hemoglobin is the protein contained in red blood cells that enables them to carry oxygen from the lungs and deliver it to all parts of the body.',
      steps: [
        'G6PD helps protect hemoglobin from damage due to the stress of infections or the use of certain medications or substances.',
        'People who have G6PD deficiency inherit a defect in the gene responsible for producing G6PD so they do not have enough of the enzyme in their blood cells.',
        'G6PD deficiency is X-linked , meaning that mainly males are affected and females are carriers of the defective gene.',
        'However, activity of the G6PD gene is highly variable, so in some people G6PD does not work quite as well as it should and in others it does not work at all.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Glucose-6-Phosphate Dehydrogenase (G6PD) Deficiency - Blood Disorders - MSD Manual Consumer Version',
