  KnowledgeEntry(
      id: 'merck-home-topic-0007-chunk-0001',
      title: 'Hemoglobin C, S-C, and E Diseases - Blood Disorders - MSD Manual Consumer Version #1 Hemoglobin C, S-C, and E Diseases By Gloria F.',
      summary: 'Hemoglobin C, S-C, and E Diseases By Gloria F.',
      steps: [
        'Gerber , MD , Johns Hopkins School of Medicine, Division of Hematology Reviewed/Revised Modified Apr 2024 v774885 Hemoglobin C, S-C, and E diseases are inherited conditions characterized by gene mutations that affect the hemoglobin (the protein that carries oxygen) in red blood cells.',
        'These red blood cells are destroyed more quickly than others, resulting in chronic anemia.',
