  KnowledgeEntry(
      id: 'merck-home-topic-0009-chunk-0001',
      title: 'Overview of Anemia - Blood Disorders - MSD Manual Consumer Version #1 Overview of Anemia By Gloria F.',
      summary: 'Overview of Anemia By Gloria F.',
      steps: [
        'Gerber , MD , Johns Hopkins School of Medicine, Division of Hematology Reviewed/Revised Apr 2024 | Modified Nov 2025 v774387 Anemia is a condition in which the number of red blood cells or the level of hemoglobin is low.',
        'Causes | Symptoms | Diagnosis | Treatment | Multimedia | Red blood cells contain hemoglobin, a protein that enables them to carry oxygen from the lungs and deliver it to all parts of the body.',
        'When the number of red blood cells or the hemoglobin level is reduced, the blood cannot carry an adequate supply of oxygen.',
        'An inadequate supply of oxygen in the tissues causes the symptoms of anemia.',
      ],
