  KnowledgeEntry(
      id: 'merck-home-topic-0016-chunk-0001',
      title: 'Hereditary Hemorrhagic Telangiectasia - Blood Disorders - MSD Manual Consumer Version #1 Hereditary Hemorrhagic Telangiectasia (Osler-Web',
      summary: 'Hereditary Hemorrhagic Telangiectasia (Osler-Weber-Rendu Syndrome) By David J.',
      steps: [
        'Kuter , MD, DPhil , Harvard Medical School Reviewed/Revised Feb 2025 | Modified Apr 2025 v775001 Hereditary hemorrhagic telangiectasia is a hereditary disorder in which blood vessels are malformed, making them fragile and prone to bleeding.',
        'Symptoms | Diagnosis | Treatment | More Information | Multimedia | Dilated blood vessels (telangiectasia) are present on the skin and the lining of the mouth, nose, and digestive tract.',
        'When blood vessels break, people develop active bleeding from these vessels, especially those within the nose.',
        'Usually the appearance of the dilated blood vessels on the lips and tongue give doctors enough information to make a diagnosis.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Hereditary Hemorrhagic Telangiectasia - Blood Disorders - MSD Manual Consumer Version',
