  KnowledgeEntry(
      id: 'merck-home-topic-0017-chunk-0001',
      title: 'Overview of Bleeding Caused by Abnormal Blood Vessels - Blood Disorders - MSD Manual Consumer Version #1 Overview of Bleeding Caused by Abnormal Blood Ve',
      summary: 'Overview of Bleeding Caused by Abnormal Blood Vessels By David J.',
      steps: [
        'Kuter , MD, DPhil , Harvard Medical School Reviewed/Revised Modified Feb 2025 v42591771 Bleeding may result from abnormalities in Platelets Coagulation factors Blood vessels Collagen is a protein that is important in maintaining strong blood vessels in the body.',
        'When collagen is abnormal or abnormal substances in the blood get into vessel walls, the vessels weaken and bleeding can develop.',
        'Fragile blood vessels cause bleeding under the skin, leading to tiny red, purple or brown spots on the skin (petechiae), slightly larger spots that look like bruises (purpura), or still larger areas of bruising (ecchymoses).',
        'They may appear red or purple in people with lighter skin and brown or black in those with darker skin.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Overview of Bleeding Caused by Abnormal Blood Vessels - Blood Disorders - MSD Manual Consumer Version',
