  KnowledgeEntry(
      id: 'merck-home-topic-0018-chunk-0002',
      title: 'Protein Disorders Causing Bruising or Bleeding - Blood Disorders - MSD Manual Consumer Version #2 Treatment depends on how severe amyloidosis is a',
      summary: 'Treatment depends on how severe amyloidosis is and what other tissues are affected.',
      steps: [
        'Cryoglobulinemia Cryoglobulinemia occurs when abnormal immunoglobulin ( antibody ) proteins in the blood clump together when blood cools (for example, when it flows through the arms and legs).',
        'These abnormal proteins are called cryoglobulins.',
        'When cryoglobulins clump together in blood vessels, the vessels may leak, leading to bruises and reddish sores on the skin.',
        'Cryoglobulins can be detected by laboratory testing.',
      ],
      contraindications: const <String>[],
