  KnowledgeEntry(
      id: 'merck-home-topic-0019-chunk-0002',
      title: 'Purpura Simplex - Blood Disorders - MSD Manual Consumer Version #2 Although doctors often do tests of the blood clo',
      summary: 'Although doctors often do tests of the blood clotting system to look for clotting abnormalities, no abnormalities are found (see also Bruising and Bleeding ).',
      steps: [
        'This condition is not serious, and no treatment is needed.',
        'However, sometimes doctors recommend that people avoid taking aspirin and This condition is not serious, and no treatment is needed.',
