  KnowledgeEntry(
      id: 'merck-home-topic-0027-chunk-0002',
      title: 'Apheresis - Blood Disorders - MSD Manual Consumer Version #2 Plasmapheresis is often done on blood from healt',
      summary: 'Plasmapheresis is often done on blood from healthy donors to obtain plasma for donation or to obtain specific substances such as clotting factors.',
      steps: [
        'Red blood cell exchange also involves apheresis.',
        'Plasma exchange In plasma exchange, the person\'s blood is removed, and the plasma is separated from the blood cells and platelets.',
        'The plasma is discarded and the blood cells and platelets are returned to the person along with a plasma-replacing fluid, such as albumin .',
        'Plasma exchange is used to treat disorders in which the person\'s plasma contains harmful substances (often antibodies).',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Apheresis - Blood Disorders - MSD Manual Consumer Version',
