  KnowledgeEntry(
      id: 'merck-home-topic-0028-chunk-0001',
      title: 'Blood Donation Process - Blood Disorders - MSD Manual Consumer Version #1 Blood Donation Process By Ravindra Sarode , MD ,',
      summary: 'Blood Donation Process By Ravindra Sarode , MD , The University of Texas Southwestern Medical Center Reviewed/Revised Modified Mar 2026 v774181 Testing Donated Blood for Infections',
      steps: [
        'People usually give 1 pint (about 450 milliliters, approximately less than one-tenth of the total amount of blood in the body).',
        'Often different components of the blood (see Blood Products ) are separated and given to different people.',
        'The entire process of donating whole blood (that is, blood with all component cells) takes about 1 hour.',
        'Blood donors must be at least 17 years old (16 in some places with consent of a parent or guardian) and weigh at least 110 pounds (50 kilograms).',
      ],
