  KnowledgeEntry(
      id: 'merck-home-topic-0031-chunk-0001',
      title: 'Precautions and Adverse Reactions During Blood Transfusion - Blood Disorders - MSD Manual Consumer Version #1 Precautions and Adverse Reactions During Blood T',
      summary: 'Precautions and Adverse Reactions During Blood Transfusion By Ravindra Sarode , MD , The University of Texas Southwestern Medical Center Reviewed/Revised Modified Mar 2026 v774346 ',
      steps: [
        'Transfusions are usually safe, but sometimes people have adverse reactions.',
        'To minimize the chance of an adverse reaction during a transfusion, health care professionals take several precautions.',
        'Before starting the transfusion, usually a few hours or even a few days beforehand, the person is cross-matched with the donor blood (not done for transfusions of plasma or platelets).',
        'In cross-matching, blood bank personnel mix a small amount of blood from the donor and the recipient to ensure there is no reaction.',
      ],
