  KnowledgeEntry(
      id: 'merck-home-topic-0034-chunk-0002',
      title: 'Hemochromatosis - Blood Disorders - MSD Manual Consumer Version #2 Causes of Hemochromatosis Hemochromatosis is her',
      summary: 'Causes of Hemochromatosis Hemochromatosis is hereditary.',
      steps: [
        'It can be caused by several different genetic mutations.',
        'The most common mutation causes Type 1 hemochromatosis Type 1 hemochromatosis involves mutation of the HFE (homeostatic iron regulator) gene.',
        'It occurs most commonly in people of Northern European ancestry.',
        'The person must inherit a mutated gene from both parents to be affected.',
      ],
