  KnowledgeEntry(
      id: 'merck-home-topic-0036-chunk-0001',
      title: 'Overview of Iron Overload - Blood Disorders - MSD Manual Consumer Version #1 Overview of Iron Overload By James Peter Adam Ha',
      summary: 'Overview of Iron Overload By James Peter Adam Hamilton , MD , Johns Hopkins University School of Medicine Reviewed/Revised Modified Jan 2025 v8485999 Iron is essential for life, so',
      steps: [
        'People lose small amounts of iron every day when cells in the skin and the digestive tract are shed, and even a healthy diet contains only a small amount of iron.',
        'Thus, people rarely have too much iron in their body.',
        'Causes of excess iron in the body (iron overload) include the following: A genetic disorder that increases iron absorption ( hemochromatosis ) Repeated blood transfusions Taking too many pills containing iron Excessive breakdown of red blood cells Women also lose iron during menstruation, so women who menstruate are unlikely to develop symptoms of iron overload until after menopause.',
        'When the body gradually takes in more iron than it needs, the excess iron is deposited in tissues throughout the body.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Overview of Iron Overload - Blood Disorders - MSD Manual Consumer Version',
