  KnowledgeEntry(
      id: 'merck-home-topic-0038-chunk-0001',
      title: 'Essential Thrombocythemia - Blood Disorders - MSD Manual Consumer Version #1 Essential Thrombocythemia (Primary Thrombocythem',
      summary: 'Essential Thrombocythemia (Primary Thrombocythemia) By Jane Liesveld , MD , James P.',
      steps: [
        'Wilmot Cancer Institute, University of Rochester Medical Center Reviewed/Revised Modified Sept 2025 v776672 Essential thrombocythemia is a myeloproliferative neoplasm in which excess platelets are produced, leading to abnormal blood clotting or bleeding.',
        'Symptoms | Diagnosis | Treatment | More Information | The hands and feet may burn, turn red or discolored, and tingle, and the fingertips may feel cold.',
        'Blood tests usually provide a diagnosis, but sometimes a bone marrow biopsy is needed.',
        'Treatments that suppress symptoms and decrease platelet production are given.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Essential Thrombocythemia - Blood Disorders - MSD Manual Consumer Version',
