  KnowledgeEntry(
      id: 'merck-home-topic-0038-chunk-0002',
      title: 'Essential Thrombocythemia - Blood Disorders - MSD Manual Consumer Version #2 Thrombocythemia can be: Primary (essential): Cau',
      summary: 'Thrombocythemia can be: Primary (essential): Caused by a disorder of platelet-forming cells Secondary: Caused by a disorder that triggers increased production by normal platelet-fo',
      steps: [
        'Sometimes younger people, especially young women are affected.',
        'Essential thrombocythemia is considered a myeloproliferative neoplasm, in which certain blood-producing cells in the bone marrow reproduce excessively.',
        'The cause is a genetic mutation usually in the Janus kinase 2 ( JAK2 ) gene, calreticulin ( CALR ) gene, or thrombopoietin receptor ( MPL ) gene.',
        'The JAK2 gene mutation causes increased activity of the JAK2 enzyme, a protein that causes excess cell production.',
      ],
      contraindications: const <String>[],
