  KnowledgeEntry(
      id: 'merck-home-topic-0039-chunk-0001',
      title: 'Myelofibrosis - Blood Disorders - MSD Manual Consumer Version #1 Myelofibrosis By Jane Liesveld , MD , James P.',
      summary: 'Myelofibrosis By Jane Liesveld , MD , James P.',
      steps: [
        'Wilmot Cancer Institute, University of Rochester Medical Center Reviewed/Revised Modified Sept 2025 v776621 Myelofibrosis is a disorder in which fibrous tissue in the bone marrow replaces the blood-producing cells, resulting in abnormally shaped red blood cells, anemia, and an enlarged spleen.',
        'Symptoms | Diagnosis | Treatment | Prognosis | More Information | Myelofibrosis may occur on its own because of certain gene mutations, or it may occur as a result of other blood disorders.',
        'People may feel tired and weak, have infections, and bleed easily.',
        'Blood tests and a bone marrow biopsy are done for diagnosis.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Myelofibrosis - Blood Disorders - MSD Manual Consumer Version',
