  KnowledgeEntry(
      id: 'merck-home-topic-0041-chunk-0001',
      title: 'Polycythemia Vera - Blood Disorders - MSD Manual Consumer Version #1 Polycythemia Vera By Jane Liesveld , MD , James',
      summary: 'Polycythemia Vera By Jane Liesveld , MD , James P.',
      steps: [
        'Wilmot Cancer Institute, University of Rochester Medical Center Reviewed/Revised Modified Sept 2025 v776545 Polycythemia vera is a myeloproliferative neoplasm of the blood-producing cells of the bone marrow that results in overproduction of all types of blood cells.',
        'Causes | Symptoms | Diagnosis | Treatment | More Information | Polycythemia vera is due to mutations in the Janus kinase 2 ( JAK2 ) gene, which produces a protein (enzyme) that stimulates excessive production of blood cells.',
        'People may feel tired and weak, light-headed, or short of breath, or develop symptoms caused by blood clots.',
        'Blood tests are done for diagnosis.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Polycythemia Vera - Blood Disorders - MSD Manual Consumer Version',
