  KnowledgeEntry(
      id: 'merck-home-topic-0043-chunk-0001',
      title: 'Secondary Thrombocythemia - Blood Disorders - MSD Manual Consumer Version #1 Secondary Thrombocythemia (Reactive Thrombocytos',
      summary: 'Secondary Thrombocythemia (Reactive Thrombocytosis ) By Jane Liesveld , MD , James P.',
      steps: [
        'Wilmot Cancer Institute, University of Rochester Medical Center Reviewed/Revised Modified Sept 2025 v18062688 Secondary thrombocythemia is excess platelets in the bloodstream that develops as a result of another disorder and rarely leads to excessive blood clotting or bleeding.',
        'Platelets (thrombocytes) are cell-like particles in the blood that help the body form blood clots.',
        'Platelets are normally produced in the bone marrow by cells called megakaryocytes.',
        'In thrombocythemia, the body produces too many platelets.',
      ],
      contraindications: const <String>[],
