  KnowledgeEntry(
      id: 'merck-home-topic-0045-chunk-0001',
      title: 'Macroglobulinemia - Blood Disorders - MSD Manual Consumer Version #1 Macroglobulinemia (Primary Macroglobulinemia; Wa',
      summary: 'Macroglobulinemia (Primary Macroglobulinemia; Waldenström Macroglobulinemia) By James R.',
      steps: [
        'Berenson , MD , Institute for Myeloma and Bone Cancer Research Reviewed/Revised Modified Aug 2024 v775720 Macroglobulinemia is a plasma cell cancer in which a single clone of plasma cells produces excessive amounts of a certain type of large antibody (IgM) called macroglobulins.',
        'Symptoms | Diagnosis | Treatment | Multimedia | Although many people have no symptoms, some people have abnormal bleeding, recurring bacterial infections, and bone fractures due to severe osteoporosis.',
        'Blood tests and bone marrow examination are needed to make the diagnosis.',
        'Macroglobulinemia is not curable, but progression can be slowed with chemotherapy.',
      ],
