  KnowledgeEntry(
      id: 'merck-home-topic-0047-chunk-0001',
      title: 'Multiple Myeloma - Blood Disorders - MSD Manual Consumer Version #1 Multiple Myeloma (Myelomatosis; Plasma Cell Myel',
      summary: 'Multiple Myeloma (Myelomatosis; Plasma Cell Myeloma) By James R.',
      steps: [
        'Berenson , MD , Institute for Myeloma and Bone Cancer Research Reviewed/Revised Modified Aug 2024 v775626 Multiple myeloma is a cancer of plasma cells in which abnormal plasma cells multiply uncontrollably in the bone marrow and occasionally in other parts of the body.',
        'Symptoms | Diagnosis | Treatment | Prognosis | Multimedia | People often have bone pain and fractures, and they may also have kidney problems, a weakened immune system (immunocompromise), weakness, and confusion.',
        'Diagnosis is made by measuring the amounts of different types of antibodies in blood and urine and confirmed by a bone marrow biopsy.',
        'Treatment often includes some combination of conventional chemotherapy agents, corticosteroids, and one or more of the following: proteasome inhibitors (such as bortezomib , carfilzomib , or ixazomib ), immunomodulatory agents (such as lenalidomide , thalidomide , pomalidomide , or venetoclax ), a nuclear export inhibitor selinexor , or monoclonal antibodies (including daratumumab , isatuximab , or elotuzumab ).',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Multiple Myeloma - Blood Disorders - MSD Manual Consumer Version',
