  KnowledgeEntry(
      id: 'merck-home-topic-0049-chunk-0001',
      title: 'Hemolytic-Uremic Syndrome (HUS) - Blood Disorders - MSD Manual Consumer Version #1 Hemolytic-Uremic Syndrome (HUS) By David J.',
      summary: 'Hemolytic-Uremic Syndrome (HUS) By David J.',
      steps: [
        'Kuter , MD, DPhil , Harvard Medical School Reviewed/Revised Modified May 2024 v26468347 Hemolytic-uremic syndrome (HUS) is a serious disorder that usually occurs in children and involves the formation of small blood clots throughout the body that block the flow of blood to vital organs such as the brain, heart, and kidneys.',
        'Symptoms | Diagnosis | Treatment | Symptoms are related to where in the body blood clots form.',
        'Diagnosis is based on the person\'s symptoms and blood test results.',
        'Treatment of HUS is support of key body functions and sometimes hemodialysis, and some people may benefit from medications such as eculizumab .',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Hemolytic-Uremic Syndrome (HUS) - Blood Disorders - MSD Manual Consumer Version',
