  KnowledgeEntry(
      id: 'merck-home-topic-0049-chunk-0002',
      title: 'Hemolytic-Uremic Syndrome (HUS) - Blood Disorders - MSD Manual Consumer Version #2 Hemolytic means that red blood cells break down,',
      summary: 'Hemolytic means that red blood cells break down, and uremic means that kidney injury causes urea (a waste product) to accumulate in the blood.',
      steps: [
        'HUS is related to thrombotic thrombocytopenic purpura (TTP), but it occurs more often in children and more often causes kidney failure , whereas TTP is more common among adults.',
        'The small blood clots that form in HUS block small blood vessels throughout the body, particularly those in the brain, heart, and kidneys.',
        'The blood vessel blockage damages organs and can break apart red blood cells that pass through partially blocked vessels.',
        'The blood clots also mean that an abnormally high number of platelets are being used up, which leads to a sharp decrease in the number of platelets in the bloodstream ( thrombocytopenia ).',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Hemolytic-Uremic Syndrome (HUS) - Blood Disorders - MSD Manual Consumer Version',
