  KnowledgeEntry(
      id: 'merck-home-topic-0050-chunk-0001',
      title: 'Immune Thrombocytopenia (ITP) - Blood Disorders - MSD Manual Consumer Version #1 Immune Thrombocytopenia (ITP) (Idiopathic Thromb',
      summary: 'Immune Thrombocytopenia (ITP) (Idiopathic Thrombocytopenic Purpura; Immune Thrombocytopenic Purpura) By David J.',
      steps: [
        'Kuter , MD, DPhil , Harvard Medical School Reviewed/Revised Modified May 2024 v26468280 Immune thrombocytopenia (ITP) is a bleeding disorder caused by decrease in the number of platelets that occurs in a person who does not have another disorder that affects platelets.',
        'In ITP, the immune system produces antibodies against a person\'s own platelets and destroys them.',
        'Symptoms | Diagnosis | Treatment | Multimedia | People may have tiny red or purple spots on their skin (petechiae) and bleed easily.',
        'Diagnosis is with blood tests to measure the number of platelets.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Immune Thrombocytopenia (ITP) - Blood Disorders - MSD Manual Consumer Version',
