  KnowledgeEntry(
      id: 'merck-home-topic-0052-chunk-0001',
      title: 'Overview of Thrombocytopenia - Blood Disorders - MSD Manual Consumer Version #1 Overview of Thrombocytopenia By David J.',
      summary: 'Overview of Thrombocytopenia By David J.',
      steps: [
        'Kuter , MD, DPhil , Harvard Medical School Reviewed/Revised Modified May 2024 v775063 Thrombocytopenia is a low number of platelets in the blood, which increases the risk of bleeding.',
        'Causes | Symptoms | Diagnosis | Treatment | Multimedia | Thrombocytopenia occurs when the bone marrow makes too few platelets or when too many platelets are destroyed or accumulate within an enlarged spleen.',
        'Bleeding in the skin and bruising occur.',
        'Doctors use blood tests to make the diagnosis and determine the cause.',
      ],
