  KnowledgeEntry(
      id: 'merck-home-topic-0057-chunk-0001',
      title: 'Overview of the Spleen - Blood Disorders - MSD Manual Consumer Version #1 Overview of the Spleen By Harry S.',
      summary: 'Overview of the Spleen By Harry S.',
      steps: [
        'Jacob , MD, DHC , University of Minnesota Medical School Reviewed/Revised Modified Dec 2024 v776748 Multimedia | The spleen, a spongy, soft organ about as big as a person’s fist, is located in the upper left part of the abdomen, just under the rib cage.',
        'The splenic artery brings blood to the spleen from the heart.',
        'Blood leaves the spleen through the splenic vein, which drains into a larger vein (the portal vein) that carries the blood to the liver.',
        'The spleen has a covering of fibrous tissue (the splenic capsule) that supports its blood vessels and lymphatic vessels.',
      ],
      contraindications: const <String>[],
