  KnowledgeEntry(
      id: 'merck-home-topic-0058-chunk-0002',
      title: 'Bone Marrow Examination - Blood Disorders - MSD Manual Consumer Version #2 Although the aspirate often provides enough info',
      summary: 'Although the aspirate often provides enough information for a diagnosis to be made, the process of drawing the marrow into the syringe breaks up the fragile bone marrow.',
      steps: [
        'As a result, determining the original arrangement of the cells is difficult.',
        'When the exact anatomic relationships of cells must be determined and the structure of the tissues evaluated, the doctor also does a core biopsy.',
        'A small core of intact bone marrow is removed with a special bone marrow biopsy needle and sliced into thin sections that are examined under a microscope.',
        'The core biopsy removes an entire piece of bone marrow and shows not only what cells are present but also how full the bone marrow is with cells and where the cells are located within the marrow.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Bone Marrow Examination - Blood Disorders - MSD Manual Consumer Version',
