  KnowledgeEntry(
      id: 'merck-home-topic-0059-chunk-0002',
      title: 'Laboratory Tests for Blood Disorders - Blood Disorders - MSD Manual Consumer Version #2 A tourniquet is applied around the upper arm, ca',
      summary: 'A tourniquet is applied around the upper arm, causing the veins below it to fill with blood so that they may be more easily seen or felt.',
      steps: [
        'After the skin immediately surrounding the vein is cleaned thoroughly, a needle is inserted into the vein.',
        'A stinging sensation is usually felt when the needle is first inserted, but otherwise the procedure is painless.',
        'Blood moves through the needle and into a syringe or collecting tube.',
        'Once enough blood is collected, the tourniquet is removed, the needle is then removed from the vein, and pressure is applied to the area to prevent bleeding from the puncture site.',
      ],
