  KnowledgeEntry(
      id: 'merck-home-topic-0061-chunk-0001',
      title: 'Overview of Blood Disorders - Blood Disorders - MSD Manual Consumer Version #1 Overview of Blood Disorders By David J.',
      summary: 'Overview of Blood Disorders By David J.',
      steps: [
        'Kuter , MD, DPhil , Harvard Medical School Reviewed/Revised Jun 2025 | Modified Jul 2025 v12856633 Disorders that affect the blood are called blood disorders or hematologic disorders.',
        'There are many blood disorders, and they can affect the quantity as well as the function of the cells in the blood (blood cells) or proteins in the blood clotting system or immune system .',
        'Some blood disorders cause the number of cells in the blood to decrease : A decreased number of red blood cells is called anemia .',
        'A decreased number of white blood cells is called leukopenia .',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Overview of Blood Disorders - Blood Disorders - MSD Manual Consumer Version',
