  KnowledgeEntry(
      id: 'merck-home-topic-0061-chunk-0002',
      title: 'Overview of Blood Disorders - Blood Disorders - MSD Manual Consumer Version #2 Other blood disorders affect proteins within the',
      summary: 'Other blood disorders affect proteins within the blood cells or blood plasma (the liquid portion of the blood): Hemoglobin, the oxygen-carrying protein inside red blood cells Immun',
      steps: [
        'Blood cells are produced in the bone marrow, and many blood proteins are made in the liver or the blood cells themselves.',
        'Blood cells and blood proteins provide the following functions: Red blood cells contain hemoglobin, which carries oxygen to every part of the body.',
        'White blood cells and antibodies fight infections and cancers.',
        'Platelets and blood clotting factors make bleeding stop or prevent bleeding from occurring.',
      ],
