  KnowledgeEntry(
      id: 'merck-home-topic-0062-chunk-0002',
      title: 'Symptoms of Blood Disorders - Blood Disorders - MSD Manual Consumer Version #2 When blood disorders cause a person\'s blood to b',
      summary: 'When blood disorders cause a person\'s blood to become thickened, the thickened (more viscous) blood may have difficulty passing through small blood vessels, decreasing blood flow t',
      steps: [
        'Affected people may experience symptoms such as shortness of breath, headaches, dizziness, and confusion.',
        'Hyperviscosity syndrome can occur in people who have multiple myeloma , in which it is caused by increased immune system proteins.',
        'Blood disorders often cause symptoms that can also occur in other disorders.',
        'For example, the weakness and shortness of breath caused by anemia can be caused by other conditions that impair oxygen delivery to the body, such as heart or lung disorders.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Symptoms of Blood Disorders - Blood Disorders - MSD Manual Consumer Version',
