  KnowledgeEntry(
      id: 'merck-home-topic-0063-chunk-0002',
      title: 'Acute Intermittent Porphyria - Blood Disorders - MSD Manual Consumer Version #2 Porphyrias are a group of different disorders, a',
      summary: 'Porphyrias are a group of different disorders, all of which except one (X-linked protoporphyria) are caused by a deficiency in one of the enzymes needed for heme production.',
      steps: [
        'Heme is a key component of several important proteins in the body.',
        'Each enzyme deficiency is caused by an abnormality in the gene (a mutation) responsible for the production of the enzyme in question.',
        'The abnormal gene is almost always inherited from one of the parents or, rarely, both.',
        'In the case of X-linked protoporphyria, the abnormal gene causes increased activity of an enzyme, resulting in too much of the porphyrin it produces.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Acute Intermittent Porphyria - Blood Disorders - MSD Manual Consumer Version',
