  KnowledgeEntry(
      id: 'merck-home-topic-0064-chunk-0002',
      title: 'Erythropoietic Protoporphyria and X-Linked Protoporphyria - Blood Disorders - MSD Manual Consumer Version #2 Afamelanotide, a medication that stimulates the',
      summary: 'Afamelanotide, a medication that stimulates the production of more melanin, can decrease sensitivity to sunlight and improve quality of life.',
      steps: [
        'Porphyrias are a group of disorders caused by abnormalities of enzymes involved in the production of heme.',
