  KnowledgeEntry(
      id: 'merck-home-topic-0065-chunk-0001',
      title: 'Overview of Porphyrias - Blood Disorders - MSD Manual Consumer Version #1 Overview of Porphyrias By Herbert L.',
      summary: 'Overview of Porphyrias By Herbert L.',
      steps: [
        'Bonkovsky , MD , Wake Forest University School of Medicine; Sean R.',
        'Rudnick , MD , Wake Forest University School of Medicine Reviewed/Revised Jan 2025 | Modified Apr 2025 v770890 Porphyrias are a group of disorders caused by deficiencies of enzymes (and, in one type, increased activity) involved in the production of heme.',
        'Classification | Diagnosis | Screening | More Information | Multimedia | Heme is a chemical compound that contains iron and gives blood its red color.',
        'Heme is a key component of several important proteins in the body.',
      ],
