  KnowledgeEntry(
      id: 'merck-home-topic-0066-chunk-0001',
      title: 'Porphyria Cutanea Tarda - Blood Disorders - MSD Manual Consumer Version #1 Porphyria Cutanea Tarda By Herbert L.',
      summary: 'Porphyria Cutanea Tarda By Herbert L.',
      steps: [
        'Bonkovsky , MD , Wake Forest University School of Medicine; Sean R.',
        'Rudnick , MD , Wake Forest University School of Medicine Reviewed/Revised Modified Jan 2025 v770930 Porphyria cutanea tarda is the most common porphyria and causes blistering and fragility of skin exposed to sunlight.',
        'Symptoms | Diagnosis | Treatment | More Information | Multimedia | People have chronically recurring blisters on the sun-exposed areas of their bodies.',
        'Excess iron can build up in the liver, causing liver damage.',
      ],
      contraindications: const <String>[],
