  KnowledgeEntry(
      id: 'merck-home-topic-0067-chunk-0001',
      title: 'Basophilic Disorders - Blood Disorders - MSD Manual Consumer Version #1 Basophilic Disorders By David C.',
      summary: 'Basophilic Disorders By David C.',
      steps: [
        'Dale , MD , University of Washington Reviewed/Revised Modified Feb 2025 v775573 Basophils are a type of white blood cell that have a role in immune surveillance (such as detecting and destroying very early cancers) and wound repair.',
        'Basophils can release histamine and other mediators and play a role in the initiation of allergic reactions .',
        'Basophils account for less than 3% of the circulating white blood cells (0 to 300 basophils per microliter of blood [0 to 0.3 × 10 9 per liter]).',
        'A decrease in the number of basophils (basopenia) can occur as a response to thyrotoxicosis , acute hypersensitivity reactions , and infections.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Basophilic Disorders - Blood Disorders - MSD Manual Consumer Version',
