  KnowledgeEntry(
      id: 'merck-home-topic-0068-chunk-0001',
      title: 'Eosinophilic Disorders - Blood Disorders - MSD Manual Consumer Version #1 Eosinophilic Disorders By David C.',
      summary: 'Eosinophilic Disorders By David C.',
      steps: [
        'Dale , MD , University of Washington Reviewed/Revised Modified Feb 2025 v775555 Eosinophils are a type of white blood cell that play an important role in the body\'s response to allergic reactions , asthma , and infection with parasites .',
        'These cells have a role in the protective immunity against certain parasites but also contribute to the inflammation that occurs in allergic disorders.',
        'Sometimes, eosinophils cause inflammation in certain organs that results in symptoms.',
        'Eosinophils usually account for less than 7% of the circulating white blood cells (100 to 500 eosinophils per microliter of blood [0.1 to 0.5 × 10 9 per liter]).',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Eosinophilic Disorders - Blood Disorders - MSD Manual Consumer Version',
