  KnowledgeEntry(
      id: 'merck-home-topic-0068-chunk-0002',
      title: 'Eosinophilic Disorders - Blood Disorders - MSD Manual Consumer Version #2 A low number of eosinophils is usually detected',
      summary: 'A low number of eosinophils is usually detected by chance when a complete blood count is done for other reasons.',
      steps: [
        'Treatment of the cause restores the normal number of eosinophils.',
        'High number of eosinophils The most common causes of a high number of eosinophils (called eosinophilia or hypereosinophilia) are Allergic disorders Infections by parasites Certain cancers Allergic disorders, including medication sensitivities , asthma (including eosinophilic asthma), allergic rhinitis , and atopic dermatitis , often increase the number of eosinophils.',
        'Many parasites , particularly ones that invade tissue, cause eosinophilia.',
        'Cancers that cause eosinophilia include Hodgkin lymphoma , leukemia , and certain myeloproliferative neoplasms .',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Eosinophilic Disorders - Blood Disorders - MSD Manual Consumer Version',
