  KnowledgeEntry(
      id: 'merck-home-topic-0070-chunk-0001',
      title: 'Lymphocytic Leukocytosis - Blood Disorders - MSD Manual Consumer Version #1 Lymphocytic Leukocytosis By David C.',
      summary: 'Lymphocytic Leukocytosis By David C.',
      steps: [
        'Dale , MD , University of Washington Reviewed/Revised Modified Feb 2025 v775520 Lymphocytic leukocytosis is an abnormally high number of lymphocytes (a type of white blood cell ) in the blood.',
        'Lymphocytes are a type of white blood cell that play several roles in the immune system, including protection against bacteria, viruses, fungi, and parasites.',
        'There are three types of lymphocytes B cells (B lymphocytes) T cells (T lymphocytes) Natural killer cells All three types can be increased in response to infections or cancer.',
        'However, in some cases only a specific type of lymphocyte is increased.',
      ],
      contraindications: const <String>[],
