  KnowledgeEntry(
      id: 'merck-home-topic-0071-chunk-0001',
      title: 'Lymphocytopenia - Blood Disorders - MSD Manual Consumer Version #1 Lymphocytopenia By David C.',
      summary: 'Lymphocytopenia By David C.',
      steps: [
        'Dale , MD , University of Washington Reviewed/Revised Feb 2025 | Modified Dec 2025 v775443 Lymphocytopenia is an abnormally low number of lymphocytes (a type of white blood cell ) in the blood.',
        'Causes | Symptoms | Diagnosis | Treatment | Many disorders can decrease the number of lymphocytes in the blood, but viral infections (including HIV infection) and undernutrition are the most common.',
        'People may have no symptoms, or they may have fever and other symptoms of an infection.',
        'A blood sample is used to make the diagnosis of lymphocytopenia, but a sample of bone marrow or lymph node may be needed to determine the cause.',
      ],
