  KnowledgeEntry(
      id: 'merck-home-topic-0072-chunk-0001',
      title: 'Monocyte Disorders - Blood Disorders - MSD Manual Consumer Version #1 Monocyte Disorders By David C.',
      summary: 'Monocyte Disorders By David C.',
      steps: [
        'Dale , MD , University of Washington Reviewed/Revised Modified Feb 2025 v775542 Monocytes are a type of white blood cell that fight certain infections and help other white blood cells remove dead or damaged tissues, destroy cancer cells, and regulate immunity against foreign substances.',
        'Monocytes are produced in the bone marrow and then enter the blood, where they account for about 1 to 10% of the circulating white blood cells (200 to 600 monocytes per microliter of blood [0.2 to 0.6 × 10 9 per liter]).',
        'After a few hours in the blood, monocytes migrate to tissues (such as spleen, liver, lungs, and bone marrow tissue), where they mature into macrophages.',
        'Macrophages are the main scavenger cells of the immune system .',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Monocyte Disorders - Blood Disorders - MSD Manual Consumer Version',
