  KnowledgeEntry(
      id: 'merck-home-topic-0073-chunk-0001',
      title: 'Neutropenia - Blood Disorders - MSD Manual Consumer Version #1 Neutropenia (Agranulocytosis; Granulocytopenia)',
      summary: 'Neutropenia (Agranulocytosis; Granulocytopenia) By David C.',
      steps: [
        'Dale , MD , University of Washington Reviewed/Revised Modified Feb 2025 v775369 Neutropenia is an abnormally low number of neutrophils (a type of white blood cell ) in the blood.',
        'Causes | Symptoms | Diagnosis | Treatment | Neutropenia, if severe, significantly increases the risk of life-threatening infection.',
        'Neutropenia is often a side effect of the treatment of cancer with chemotherapy or radiation therapy.',
        'Doctors suspect neutropenia in people who have frequent or unusual infections.',
      ],
