  KnowledgeEntry(
      id: 'merck-home-topic-0073-chunk-0002',
      title: 'Neutropenia - Blood Disorders - MSD Manual Consumer Version #2 Neutrophils usually constitute about 45 to 75% o',
      summary: 'Neutrophils usually constitute about 45 to 75% of all white blood cells in the bloodstream.',
      steps: [
        'Without the key defense provided by neutrophils, people have problems controlling infections and are at risk of dying from an infection.',
        'Neutropenia may resolve quickly when the infection resolves or the exposure stops.',
        'Chronic neutropenia may last for months or years.',
        'Severity of neutropenia The typical lower limit of the neutrophil count is about 1500 cells per microliter of blood (1.5 × 10 9 cells per liter).',
      ],
      contraindications: const <String>[],
