  KnowledgeEntry(
      id: 'merck-home-topic-0074-chunk-0002',
      title: 'Neutrophilic Leukocytosis - Blood Disorders - MSD Manual Consumer Version #2 Inflammatory disorders, including autoimmune dis',
      summary: 'Inflammatory disorders, including autoimmune disorders such as rheumatoid arthritis , can cause an increase in the number and activity of neutrophils.',
      steps: [
        'Some medications, such as corticosteroids, also lead to an increased number of neutrophils in the blood.',
        'Myeloid leukemias can lead to an increased number of immature or mature neutrophils in the blood.',
