  KnowledgeEntry(
      id: 'merck-home-topic-0075-chunk-0002',
      title: 'Overview of White Blood Cell Disorders - Blood Disorders - MSD Manual Consumer Version #2 The total white blood cell count normally ranges',
      summary: 'The total white blood cell count normally ranges between 4,000 and 11,000 cells per microliter (4 to 11 × 10 9 per liter).',
      steps: [
        'The proportion of each of the five major types of white blood cells and the total number of cells of each type in a given volume of blood can be determined through laboratory tests.',
        'Too few or too many white blood cells indicates a disorder.',
        'Leukopenia, a decrease in the number of white blood cells to fewer than 4,000 cells per microliter of blood (4 × 10 9 per liter), frequently makes people more susceptible to infections.',
        'Leukocytosis, an increase in the number of white blood cells to more than 11,000 cells per microliter of blood (11 × 10 9 per liter), is often caused by the normal response of the body to help fight an infection, or to some medications such as corticosteroids.',
      ],
      contraindications: const <String>[],
