  KnowledgeEntry(
      id: 'merck-home-topic-0089-chunk-0001',
      title: 'Achilles Tendon Bursitis - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Achilles Tendon Bursitis By James C.',
      summary: 'Achilles Tendon Bursitis By James C.',
      steps: [
        'Connors , DPM , Kent State University College of Podiatric Medicine Reviewed/Revised Modified Oct 2025 v26370774 Achilles tendon bursitis is inflammation of the fluid-filled sac (bursa) located either between the skin of the back of the heel and the Achilles tendon (called posterior Achilles tendon bursitis) or in front of the attachment of the Achilles tendon to the heel bone (called anterior Achilles tendon bursitis or retrocalcaneal bursitis).',
        'Symptoms | Diagnosis | Treatment | Multimedia | Typical symptoms include swelling, warmth, pain, and a tender spot at the back of the heel.',
        'The diagnosis is based on symptoms, an examination, and sometimes x-rays.',
        'Treatment is aimed at relieving the inflammation and, depending on the location of the Achilles tendon bursitis, eliminating the pressure on the back of the heel.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Achilles Tendon Bursitis - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version',
