  KnowledgeEntry(
      id: 'merck-home-topic-0089-chunk-0002',
      title: 'Achilles Tendon Bursitis - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #2 Bursitis is painful inflammation of a bursa (a f',
      summary: 'Bursitis is painful inflammation of a bursa (a flat, fluid-filled sac that provides cushioning and reduces friction in areas where skin, muscles, tendons, and ligaments rub over bo',
      steps: [
        'Posterior Achilles tendon bursitis occurs mainly in young women but can develop in men.',
        'Walking in a way that repeatedly presses the soft tissue behind the heel against the stiff back support of a shoe can cause or aggravate the bursitis.',
        'Shoes that taper sharply inward toward the posterior heel (such as high-heeled shoes or pumps) can cause or worsen an enlargement of the bone of the back of the heel (called pump bump or Haglund deformity), which contributes to posterior Achilles tendon bursitis.',
        'Anterior Achilles tendon bursitis (also called Albert disease or retrocalcaneal bursitis) can be caused by any condition that puts extra strain on the Achilles tendon.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Achilles Tendon Bursitis - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version',
