  KnowledgeEntry(
      id: 'merck-home-topic-0090-chunk-0002',
      title: 'Achilles Tendon Enthesopathy - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #2 Diagnosis of Achilles Tendon Enthesopathy A doct',
      summary: 'Diagnosis of Achilles Tendon Enthesopathy A doctor\'s examination The diagnosis of Achilles tendon enthesopathy is based on a physical examination of the tendon.',
      steps: [
        'The diagnosis is confirmed if people have tenderness of the tendon where it attaches to the heel bone.',
        'Manually bending (flexing) the ankle upwards during the examination usually makes the pain worse.',
        'Treatment of Achilles Tendon Enthesopathy Stretching, night splints, and heel lifts If present, treatment of spondyloarthritis Doing exercises that stretch the calf muscles for 10 minutes 2 to 3 times daily can help people with Achilles tendon enthesopathy.',
        'A person can stretch the calf muscle and Achilles tendon while facing a wall at arms’ length, with the knees straight and the foot bent upward.',
      ],
