  KnowledgeEntry(
      id: 'merck-home-topic-0091-chunk-0002',
      title: 'Bunion - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #2 Hallux Valgus With a Bunion A hallux valgus is w',
      summary: 'Hallux Valgus With a Bunion A hallux valgus is when the base of the big toe abnormally points outward away from the foot and the tip of the big toe tilts in toward the second toe.',
      steps: [
        'A bunion is the enlargement at the base of the big toe caused by the hallux valgus deformity.',
        'A bursa (a fluid-filled sac) may develop over the joint and may become painful.',
        'When the base of the big toe abnormally points outward and the tip of the big toe points inward (toward the second toe), the condition is called hallux valgus .',
        'Hallux valgus causes a bunion.',
      ],
