  KnowledgeEntry(
      id: 'merck-home-topic-0092-chunk-0002',
      title: 'Damage to Nerves in the Foot - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #2 Pain in the ball of the foot may be caused by lo',
      summary: 'Pain in the ball of the foot may be caused by long-standing irritation of the nerves.',
      steps: [
        'The irritation often causes the nerves to enlarge and noncancerous (benign) thickening of the tissue surrounding the nerve (neuromas) to form, usually between the base of the third and fourth toes (Morton neuroma).',
        'However, these irritated nerves may occur between any of the toes.',
        'Neuromas usually develop in only one foot and are more common among women.',
        'Many factors contribute to nerve irritation, particularly shoes that offer no support or are tight fitting.',
      ],
      contraindications: const <String>[],
