  KnowledgeEntry(
      id: 'merck-home-topic-0093-chunk-0001',
      title: 'Freiberg Disease - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Freiberg Disease (Freiberg Infraction) By James',
      summary: 'Freiberg Disease (Freiberg Infraction) By James C.',
      steps: [
        'Connors , DPM , Kent State University College of Podiatric Medicine Reviewed/Revised Modified Oct 2025 v26371096 Freiberg disease is death of the tissue (necrosis) of parts of the bones in the ball of the foot, usually next to the big toe (the second metatarsal head).',
        'Symptoms | Diagnosis | Treatment | Multimedia | (See also Overview of Foot Problems .) Freiberg disease is a cause of pain in the ball of the foot ( metatarsalgia ).',
        'The cause is injury to the bone.',
        'This disorder usually occurs in girls who are going through puberty and who are growing rapidly or in people in whom the bone connected to the base of the big toe (the first metatarsal bone) is short or the second metatarsal bone is long.',
      ],
      contraindications: const <String>[],
