  KnowledgeEntry(
      id: 'merck-home-topic-0096-chunk-0001',
      title: 'Medial and Lateral Plantar Nerve Entrapment - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Medial and Lateral Plantar Nerve Entrapment By J',
      summary: 'Medial and Lateral Plantar Nerve Entrapment By James C.',
      steps: [
        'Connors , DPM , Kent State University College of Podiatric Medicine Reviewed/Revised Modified Oct 2025 v26371222 Medial and lateral plantar nerve entrapment is compression of nerve branches at the inner heel (the medial or lateral branches of the plantar nerve) that causes pain.',
        'Symptoms | Diagnosis | Treatment | The nerve branches are pinched (compressed) between bone, ligaments, and other connective tissues, causing pain.',
        'The pain is made worse when ankle motion and certain shoes or activities such as running put additional pressure on the pinched nerves.',
        '(See also Overview of Foot Problems .) Symptoms of Medial and Lateral Plantar Nerve Entrapment Symptoms of medial and lateral plantar nerve entrapment include almost constant pain, whether walking or sitting.',
      ],
      contraindications: const <String>[],
