  KnowledgeEntry(
      id: 'merck-home-topic-0100-chunk-0001',
      title: 'Plantar Fasciitis - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Plantar Fasciitis (Plantar Fasciosis) By James C',
      summary: 'Plantar Fasciitis (Plantar Fasciosis) By James C.',
      steps: [
        'Connors , DPM , Kent State University College of Podiatric Medicine Reviewed/Revised Modified Oct 2025 v26371341 Plantar fasciitis is pain originating from the dense band of tissue called the plantar fascia that extends from the bottom of the heel bone to the base of the toes (ball of the foot).',
        'Symptoms | Diagnosis | Treatment | Multimedia | The connective tissue between the heel and ball of the foot may become damaged and painful.',
        'Pain, which is often worse when first bearing weight in the morning and after periods of rest, is felt at the bottom of the heel.',
        'The diagnosis is based on an examination of the foot and imaging tests.',
      ],
