  KnowledgeEntry(
      id: 'merck-home-topic-0101-chunk-0001',
      title: 'Plantar Fibromatosis - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Plantar Fibromatosis By James C.',
      summary: 'Plantar Fibromatosis By James C.',
      steps: [
        'Connors , DPM , Kent State University College of Podiatric Medicine Reviewed/Revised Modified Oct 2025 v26371429 Plantar fibromatosis is a noncancerous (benign) enlargement of connective tissue in the sole (the plantar fascia).',
        'In plantar fibromatosis, bumps develop on the sole and are most obvious when the big toe is pulled back and the foot is bent upward toward the leg.',
        'Many people also have bumps in the palms, usually located near the fourth knuckle.',
        'Doctors base the diagnosis of plantar fibromatosis on an examination of the foot.',
      ],
