  KnowledgeEntry(
      id: 'merck-home-topic-0107-chunk-0001',
      title: 'Calcium Pyrophosphate Deposition Disease - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Calcium Pyrophosphate Deposition Disease (Pseudo',
      summary: 'Calcium Pyrophosphate Deposition Disease (Pseudogout; CPP crystal arthritis) By Sarah F.',
      steps: [
        'Keller , MD, MA , Cleveland Clinic, Department of Rheumatic and Immunologic Diseases Reviewed/Revised Modified Jul 2025 v731926 Calcium pyrophosphate deposition (CPPD) disease (sometimes still called pseudogout or CPP crystal arthritis) is a disorder caused by deposits of calcium pyrophosphate crystals in the joint cartilage, leading to intermittent attacks of painful joint inflammation similar to gout or a chronic arthritis similar to rheumatoid arthritis.',
        'Causes | Symptoms | Diagnosis | Treatment | Prognosis | Crystals accumulate in the fluid and cartilage of the joints, and cause varying degrees of inflammation and tissue damage.',
        'The diagnosis is confirmed by finding CPP crystals in joint fluid.',
        'Treatment is with medications to relieve the pain and swelling resulting from the inflammation, although none reduce the CPP crystal deposits in the joints.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Calcium Pyrophosphate Deposition Disease - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version',
