  KnowledgeEntry(
      id: 'merck-home-topic-0112-chunk-0002',
      title: 'De Quervain Syndrome - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #2 To detect tenderness, doctors have people bend t',
      summary: 'To detect tenderness, doctors have people bend their thumb into their palm and wrap their fingers over the thumb.',
      steps: [
        'Then people bend their wrist away from the thumb.',
        'People are likely to have De Quervain syndrome if this movement causes pain at the same side of the wrist as the thumb.',
        'Treatment of De Quervain Syndrome Corticosteroid injection Thumb splint Sometimes surgery Movements that cause pain in people with De Quervain syndrome should be avoided.',
        'Rest, warm soaks, and nonsteroidal anti-inflammatory drugs ( NSAIDs ) may help people with mild symptoms.',
      ],
