  KnowledgeEntry(
      id: 'merck-home-topic-0127-chunk-0002',
      title: 'Ankylosing Spondylitis - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #2 The cause of ankylosing spondylitis is not known',
      summary: 'The cause of ankylosing spondylitis is not known, but the disease tends to run in families, indicating that genetics plays a role.',
      steps: [
        'Ankylosing spondylitis is 10 to 20 times more common among people whose parents or siblings have it.',
        'The HLA-B27 gene is present in 90% of White people who have ankylosing spondylitis, but it is also present in up to 10% of the general population depending on ethnicity.',
        'However, having the HLA-B27 gene does not mean that a person has or will develop ankylosing spondylitis.',
        'For example, only 50% of identical twins both have the disorder, which suggests that unknown environmental factors also may be involved.',
      ],
      contraindications: const <String>[],
