  KnowledgeEntry(
      id: 'merck-home-topic-0133-chunk-0002',
      title: 'Rheumatoid Arthritis (RA) - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #2 Worldwide, rheumatoid arthritis develops in abou',
      summary: 'Worldwide, rheumatoid arthritis develops in about 0.5% of the population, regardless of race or country of origin, affecting women 2 to 3 times more often than men.',
      steps: [
        'Usually, rheumatoid arthritis first appears between 35 years and 50 years of age, but it may occur at any age.',
        'A disorder similar to rheumatoid arthritis can occur in children.',
        'The disease is then called juvenile idiopathic arthritis .',
        'However, the prognosis for juvenile idiopathic arthritis is often somewhat different.',
      ],
