  KnowledgeEntry(
      id: 'merck-home-topic-0136-chunk-0001',
      title: 'Low Back Pain - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Low Back Pain By Peter J.',
      summary: 'Low Back Pain By Peter J.',
      steps: [
        'Moley , MD , Hospital for Special Surgery Reviewed/Revised Nov 2024 | Modified Jul 2025 v744396 Causes | Evaluation | Prevention | Treatment | Key Points | Multimedia | Low back pain and neck pain are among the most common reasons for health care visits.',
        'The pain usually results from problems with the musculoskeletal system —most notably the spine, including the bones of the spine (back bones, or vertebrae), discs, and the muscles and ligaments that support it.',
        'Occasionally, low back pain results from a disorder that does not involve the musculoskeletal system.',
        'Low back pain becomes more common as people age, affecting more than half of people over 65.',
      ],
      contraindications: const <String>[],
      escalation: '原始来源：MSD Manual / Low Back Pain - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version',
