  KnowledgeEntry(
      id: 'merck-home-topic-0141-chunk-0001',
      title: 'Baker Cysts - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Baker Cysts (Baker\'s Cysts; Popliteal Cysts) By',
      summary: 'Baker Cysts (Baker\'s Cysts; Popliteal Cysts) By Deepan S.',
      steps: [
        'Dalal , MD, MPH , Brown University Reviewed/Revised Modified Mar 2024 v38404692 Baker cysts are small sacs filled with joint (synovial) fluid that form in an extension of the joint capsule behind the knee.',
        'Diagnosis | Treatment | A Baker cyst results from an accumulation of trapped joint fluid, which bulges from the joint capsule behind the knee as a protruding sac.',
        'Causes of the joint fluid accumulation include rheumatoid arthritis , osteoarthritis , other inflammatory joint diseases and overuse of the knees.',
        'Baker cysts often do not cause symptoms but may become noticeable when they become swollen and cause discomfort at the back of the knee.',
      ],
      contraindications: const <String>[],
