  KnowledgeEntry(
      id: 'merck-home-topic-0146-chunk-0001',
      title: 'Osteonecrosis - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Osteonecrosis (Avascular Necrosis; Aseptic Necro',
      summary: 'Osteonecrosis (Avascular Necrosis; Aseptic Necrosis; Ischemic Necrosis of Bone) By Stuart B.',
      steps: [
        'Goodman , MD, PhD , Stanford University Reviewed/Revised Modified Dec 2024 v729358 Osteonecrosis is the death of a segment of bone caused by an impaired blood supply.',
        'Causes | Symptoms | Diagnosis | Treatment | Prevention | Multimedia | Osteonecrosis is most commonly caused by an injury but can also occur without an injury.',
        'Typical symptoms include pain, limited range of motion of the affected joint, and, when the leg is affected, a limp.',
        'The diagnosis is based on symptoms, the person\'s risk of osteonecrosis, and the results of x-rays and magnetic resonance imaging.',
      ],
