  KnowledgeEntry(
      id: 'merck-home-topic-0147-chunk-0001',
      title: 'Osteoporosis - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 HEALTHY LIVING Osteoporosis By Marcy B.',
      summary: 'HEALTHY LIVING Osteoporosis By Marcy B.',
      steps: [
        'Bolster , MD , Harvard Medical School Reviewed/Revised Modified Jul 2025 v728818 Osteoporosis is a condition in which a decrease in the density of bones weakens the bones, making breaks (fractures) likely.',
        'Types of Osteoporosis | Symptoms | Diagnosis | Treatment | Prevention | More Information | Multimedia | Aging, estrogen deficiency, low vitamin D or calcium intake, and certain disorders can decrease the amounts of the components that maintain bone density and strength.',
        'Osteoporosis may not cause symptoms until a bone fracture occurs.',
        'Fractures can occur with little or no force and may occur after a minor fall.',
      ],
      contraindications: const <String>[],
