  KnowledgeEntry(
      id: 'merck-home-topic-0148-chunk-0001',
      title: 'Paget Disease of Bone - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Paget Disease of Bone (Osteitis Deformans; Paget',
      summary: 'Paget Disease of Bone (Osteitis Deformans; Paget\'s Disease of Bone) By Julia F.',
      steps: [
        'Charles , MD, PhD , Brigham and Women&#x27;s Hospital Reviewed/Revised Jun 2025 | Modified Jul 2025 v729048 Paget disease of bone is a chronic disorder of the skeleton in which areas of bone undergo abnormal turnover, resulting in areas of enlarged and softened bone.',
        'Causes | Symptoms | Diagnosis | Treatment | Prognosis | Multimedia | The breakdown and formation of bone increase, resulting in bones that are thicker, but weaker, than normal.',
        'Symptoms may be absent or may include bone pain, bone deformity, arthritis, and painful nerve compression.',
        'X-rays show the bone abnormalities.',
      ],
      contraindications: const <String>[],
