  KnowledgeEntry(
      id: 'merck-home-topic-0149-chunk-0001',
      title: 'Difficulty Moving - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Difficulty Moving By Alexandra Villa-Forte , MD,',
      summary: 'Difficulty Moving By Alexandra Villa-Forte , MD, MPH , Cleveland Clinic Reviewed/Revised Modified Apr 2025 v1155858 A person may have difficulty moving all or part of the body.',
      steps: [
        'Causes | Diagnosis | Treatment | Causes of Difficulty Moving Moving may be difficult because of disorders that restrict joint motion or that cause weakness, stiffness , tremor , or difficulty initiating movement (for example, Parkinson disease ).',
        'Movement may also be limited when motion causes pain .',
        'People with pain in the muscles, ligaments, bones, or joints (see Introduction to the Biology of the Musculoskeletal System ) tend to consciously and unconsciously limit motion.',
        'This limitation of motion often gives the impression of weakness even though the nervous system and muscles are able to generate movement.',
      ],
