  KnowledgeEntry(
      id: 'merck-home-topic-0150-chunk-0001',
      title: 'Introduction to Symptoms of Musculoskeletal Disorders - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #1 Introduction to Symptoms of Musculoskeletal Diso',
      summary: 'Introduction to Symptoms of Musculoskeletal Disorders By Alexandra Villa-Forte , MD, MPH , Cleveland Clinic Reviewed/Revised Modified Apr 2025 v1155790 Musculoskeletal symptoms are',
      steps: [
        'Common symptoms of musculoskeletal disorders include the following: Pain Weakness Stiffness Joint noises Decreased range of motion Inflammation may cause pain, swelling, warmth, tenderness, impaired function, and sometimes redness of the overlying skin.',
        'Inflammation can result from many different musculoskeletal disorders, such as autoimmune disorders (for example, rheumatoid arthritis ) and infections.',
        'When inflammation affects a joint, fluid may accumulate inside the joint, causing pain, swelling, and decreased range of motion.',
        'Test your Knowledge Take a Quiz!',
      ],
      contraindications: const <String>[],
