  KnowledgeEntry(
      id: 'merck-home-topic-0172-chunk-0002',
      title: 'Polymyalgia Rheumatica - Bone, Joint, and Muscle Disorders - MSD Manual Consumer Version #2 Symptoms of Polymyalgia Rheumatica Symptoms of p',
      summary: 'Symptoms of Polymyalgia Rheumatica Symptoms of polymyalgia rheumatica may develop suddenly or gradually.',
      steps: [
        'Severe pain and stiffness occur in the neck, shoulders, upper and lower back, and hips.',
        'The stiffness and discomfort are worse in the morning and after periods of inactivity and are occasionally severe enough to prevent people from getting out of bed and from doing simple activities.',
        'People may feel weak, but the muscles are not damaged or weak.',
        'People may also have a fever, feel generally unwell or depressed, and lose weight unintentionally.',
      ],
