  KnowledgeEntry(
      id: 'merck-home-topic-0175-chunk-0001',
      title: 'Horner Syndrome - Brain, Spinal Cord, and Nerve Disorders - MSD Manual Consumer Version #1 Horner Syndrome (Horner\'s Syndrome) By Elizabeth',
      summary: 'Horner Syndrome (Horner\'s Syndrome) By Elizabeth Coon , MD , Mayo Clinic Reviewed/Revised May 2025 | Modified Jul 2025 v746509 Horner syndrome affects one side of the face, causing',
      steps: [
        'The cause is disruption of the nerve fibers that connect the brain to the eye.',
        'Causes | Symptoms | Diagnosis | Treatment | Multimedia | Horner syndrome may occur on its own or result from a disorder that disrupts nerve fibers connecting the brain with the eye.',
        'The upper eyelid droops, the pupil remains small, and the affected side of the face may sweat less.',
        'Doctors test the pupil to see whether it can widen and may do imaging tests to look for a cause.',
      ],
