  KnowledgeEntry(
      id: 'merck-home-topic-0176-chunk-0001',
      title: 'Multiple System Atrophy (MSA) - Brain, Spinal Cord, and Nerve Disorders - MSD Manual Consumer Version #1 Multiple System Atrophy (MSA) By Elizabeth Coon',
      summary: 'Multiple System Atrophy (MSA) By Elizabeth Coon , MD , Mayo Clinic Reviewed/Revised May 2025 | Modified Jul 2025 v742723 Multiple system atrophy is a progressive, fatal disorder th',
      steps: [
        'Causes | Symptoms | Diagnosis | Treatment | Multimedia | The parts of the brain that control movement and autonomic processes degenerate.',
        'Symptoms include symptoms that resemble those of Parkinson disease, loss of coordination, low blood pressure when a person stands (orthostatic hypotension), problems with urination, and constipation.',
        'Doctors base the diagnosis on a person\'s response to levodopa (used to treat Parkinson disease) and results of magnetic resonance imaging and tests of autonomic function.',
      ],
      contraindications: const <String>[],
