  KnowledgeEntry(
      id: 'merck-home-topic-0177-chunk-0001',
      title: 'Overview of the Autonomic Nervous System - Brain, Spinal Cord, and Nerve Disorders - MSD Manual Consumer Version #1 Overview of the Autonomic Nervous System By Eliz',
      summary: 'Overview of the Autonomic Nervous System By Elizabeth Coon , MD , Mayo Clinic Reviewed/Revised May 2025 | Modified Jul 2025 v746348 Causes | Symptoms | Diagnosis | Treatment | Mult',
      steps: [
        'This system works automatically (autonomously), without a person’s conscious effort.',
        'Disorders of the autonomic nervous system can affect any body part or process.',
        'Autonomic disorders may be reversible or progressive.',
        'Anatomy of the autonomic nervous system The autonomic nervous system is the part of the nervous system that supplies the internal organs, including the blood vessels, stomach, intestine, liver, kidneys, bladder, genitals, lungs, pupils, heart, and sweat, salivary, and digestive glands.',
      ],
